# Iterative DFS using explicit stack
def dfs_iterative(graph, start):
    visited = set()
    stack = [start]
    order = []

    while stack:
        vertex = stack.pop()
        if vertex not in visited:
            visited.add(vertex)
            order.append(vertex)
            # Push neighbours (reversed for consistent left-to-right order)
            for neighbour in reversed(graph[vertex]):
                if neighbour not in visited:
                    stack.append(neighbour)

    return order

import heapq

def dijkstra(graph, start):
    # graph[u] = [(weight, v), ...]
    distances = {vertex: float('inf') for vertex in graph}
    distances[start] = 0

    # Min-heap: (distance, vertex)
    heap = [(0, start)]

    while heap:
        current_dist, current_vertex = heapq.heappop(heap)

        # Skip if we already found a better path
        if current_dist > distances[current_vertex]:
            continue

        for weight, neighbour in graph[current_vertex]:
            distance = current_dist + weight

            if distance < distances[neighbour]:
                distances[neighbour] = distance
                heapq.heappush(heap, (distance, neighbour))

    return distances

