def bellman_ford(vertices, edges, start):
    # edges: list of (from, to, weight)
    distances = {v: float('inf') for v in vertices}
    distances[start] = 0

    for _ in range(len(vertices) - 1):
        for u, v, weight in edges:
            if distances[u] + weight < distances[v]:
                distances[v] = distances[u] + weight

    # Check for negative cycles
    for u, v, weight in edges:
        if distances[u] + weight < distances[v]:
            return None  # Negative cycle detected

    return distances

def floyd_warshall(graph, n):
    # graph is a V×V matrix; graph[i][j] = weight or inf if no edge
    dist = [row[:] for row in graph]  # copy

    for k in range(n):
        for i in range(n):
            for j in range(n):
                if dist[i][k] + dist[k][j] < dist[i][j]:
                    dist[i][j] = dist[i][k] + dist[k][j]

    return dist

from collections import deque

def topological_sort_kahn(graph, vertices):
    # Compute in-degrees for each vertex
    in_degree = {v: 0 for v in vertices}
    for u in graph:
        for v in graph[u]:
            in_degree[v] += 1

    # Start with all vertices that have no prerequisites (in-degree = 0)
    queue = deque([v for v in vertices if in_degree[v] == 0])
    order = []

    while queue:
        vertex = queue.popleft()
        order.append(vertex)

        for neighbour in graph.get(vertex, []):
            in_degree[neighbour] -= 1
            if in_degree[neighbour] == 0:
                queue.append(neighbour)

    if len(order) != len(vertices):
        return None  # Cycle detected — topological sort impossible

    return order

